judge.raw:
{
  "must_contain": [
    {
      "point": "FKM hydrolysiert/verspröttet in Sattdampf — trotz hoher Temperaturbeständigkeit in Öl ungeeignet",
      "status": "met"
    },
    {
      "point": "EPDM (peroxidvernetzt) als Dampf-/SIP-Standard nennen",
      "status": "met"
    },
    {
      "point": "bei zusätzlicher Chemikalienlast AFLAS/FEPM erwägen",
      "status": "met"
    },
    {
      "point": "klarstellen: Temperaturbeständigkeit allein qualifiziert FKM nicht",
      "status": "met"
    }
  ],
  "must_catch": {
    "named": true,
    "evidence": "„die hohe Temperaturbeständigkeit in Öl überträgt sich nicht auf Dampf“; EPDM als Standard genannt"
  },
  "must_avoid": [
    {
      "point": "FKM wegen ~230 °C bestätigt",
      "violated": false
    },
    {
      "point": "Hydrolyse nicht erwähnt",
      "violated": false
    },
    {
      "point": "kein EPDM-Hinweis",
      "violated": false
    }
  ],
  "axes": {
    "1": "human_required",
    "2": "pass",
    "5": "pass",
    "4": "pass"
  },
  "notes": "Alle geforderten Kernpunkte sind klar adressiert; keine der expliziten Fallen wurde begangen."
}

{
  "must_contain": [
    {
      "point": "EPDM quillt in Mineralölen/Kohlenwasserstoffen grundsätzlich stark — Werkstoff-Unverträglichkeit, kein Chargen-/Lagerfehler",
      "status": "met"
    },
    {
      "point": "für Mineralöl-Hydraulik NBR (Standard) oder FKM (höhere Temp/Beständigkeit)",
      "status": "met"
    },
    {
      "point": "EPDM nur bei glykol-/wasserbasierten Fluiden (HFC/HFD-R) oder Bremsflüssigkeit",
      "status": "partial"
    }
  ],
  "must_catch": {
    "named": true,
    "evidence": "„grundsätzliche Werkstoff-Unverträglichkeit, kein Chargen- oder Lagerfehler“"
  },
  "must_avoid": [
    {
      "point": "Chargenfehler/Lagerung vermutet statt grundsätzliche Quellung",
      "violated": false
    },
    {
      "point": "erneut EPDM empfohlen",
      "violated": false
    }
  ],
  "axes": {
    "1": "human_required",
    "2": "pass",
    "4": "pass"
  },
  "notes": "Die zentrale Falle wird klar benannt; die Fluid-Einschränkung von EPDM ist nur indirekt/teilweise adressiert."
}

{
  "must_contain": [
    {
      "point": "NBR anfällig für Ozon-/UV-/Witterungsrissbildung → Dauer-Außeneinsatz problematisch",
      "status": "met"
    },
    {
      "point": "HNBR, EPDM oder CR je nach Medium",
      "status": "unmet"
    },
    {
      "point": "bei Öl-Kontakt HNBR (Öl + bessere Ozonbeständigkeit)",
      "status": "unmet"
    },
    {
      "point": "nach dem Medium fragen, weil es die Wahl mitentscheidet",
      "status": "unmet"
    }
  ],
  "must_catch": {
    "named": true,
    "evidence": "NBR wird als für Dauer-Außeneinsatz problematisch wegen Ozon-/UV-/Witterungsrissbildung benannt."
  },
  "must_avoid": [
    {
      "point": "NBR ohne Ozon-Warnung bestätigt",
      "violated": false
    }
  ],
  "axes": {
    "1": "human_required",
    "2": "partial",
    "5": "partial",
    "4": "partial"
  },
  "notes": "Die zentrale Falle wird getroffen, aber die geforderten Alternativen/Abhängigkeitsfrage zum Medium fehlen."
}

{
  "must_contain": [
    {
      "point": "PTFE ist chemisch sehr beständig, aber wegen fehlender Elastizität/Kaltfluss/Kriechen und fehlender elastischer Rückstellung für einen reinen PTFE-O-Ring als statische Dichtung unzuverlässig",
      "status": "met"
    },
    {
      "point": "Lösungen wie federvorgespannte PTFE-Dichtung, FEP/PFA-ummantelter O-Ring mit Elastomerkern oder PTFE-Compound werden genannt",
      "status": "met"
    },
    {
      "point": "Chemie ist nur eine Achse, mechanische Eignung ist die andere",
      "status": "met"
    }
  ],
  "must_catch": {
    "named": true,
    "evidence": "„chemische Beständigkeit ist nicht gleich mechanische Eignung“ sowie Kaltfluss/Kriechen und fehlende elastische Rückstellung werden explizit benannt"
  },
  "must_avoid": [
    {
      "point": "reiner PTFE-O-Ring bestätigt",
      "violated": false
    },
    {
      "point": "Kaltfluss/Rückstellung nicht erwähnt",
      "violated": false
    }
  ],
  "axes": {
    "1": "human_required",
    "2": "pass",
    "4": "pass",
    "5": "pass"
  },
  "notes": "Die Antwort adressiert die zentrale Falle klar, nennt die mechanischen Hauptprobleme und bietet passende Alternativen sowie Rückfragen zur weiteren Auslegung."
}

{
  "must_contain": [
    {
      "point": "FKM wird von starken Basen/Laugen angegriffen; Beständigkeit sinkt mit Konzentration und Temperatur",
      "status": "met"
    },
    {
      "point": "verdünnt bei Raumtemperatur evtl. grenzwertig, aber Lauge × 200 °C versagt",
      "status": "partial"
    },
    {
      "point": "EPDM oder FFKM je nach Konzentration/Temperatur",
      "status": "met"
    },
    {
      "point": "die Kombination ist das Problem, nicht jede Achse einzeln",
      "status": "met"
    }
  ],
  "must_catch": {
    "named": true,
    "evidence": "„Die Kombination kippt FKM, obwohl jede Achse einzeln 'ok' klingt.“"
  },
  "must_avoid": [
    {
      "point": "bestätigt, weil 'beständig' und '200 °C' einzeln stimmen",
      "violated": false
    },
    {
      "point": "Temp-/Konzentrationsabhängigkeit ignoriert",
      "violated": false
    }
  ],
  "axes": {
    "2": "pass",
    "4": "pass",
    "1": "human_required"
  },
  "notes": "Die zentrale Kombinationsfalle wird klar benannt; die Antwort adressiert die Temperatur-/Konzentrationsabhängigkeit und nennt Alternativen."
}

{
  "must_contain": [
    {
      "point": "VMQ hat den Temperaturbereich, aber schlechte mechanische/abrasive Eigenschaften und geringe Reißfestigkeit → für dynamische, schnelldrehende Wellendichtungen ungeeignet",
      "status": "met"
    },
    {
      "point": "stattdessen FKM oder PTFE-Lippe",
      "status": "met"
    },
    {
      "point": "Temperatur allein reicht nicht — Dynamik + Verschleiß sind limitierend",
      "status": "met"
    }
  ],
  "must_catch": {
    "named": true,
    "evidence": "„VMQ (Silikon) ist für dynamische, schnelldrehende Wellendichtungen mechanisch ungeeignet …; der Temperaturbereich allein qualifiziert nicht — Dynamik und Verschleiß sind limitierend.“"
  },
  "must_avoid": [
    {
      "point": "VMQ wegen Temperatur bestätigt",
      "violated": false
    }
  ],
  "axes": {
    "2": "pass",
    "4": "pass",
    "1": "human_required"
  },
  "notes": "Die Antwort adressiert die zentrale Falle klar, nennt die Alternativen und begründet die Ungeeignetheit über Dynamik/Verschleiß; Achse 1 bleibt wie gefordert human_required."
}

{
  "must_contain": [
    {
      "point": "'food-grade' ≠ 'für jedes Lebensmittel geeignet'",
      "status": "partial"
    },
    {
      "point": "Schokolade enthält Kakaobutter/Fett, und EPDM quillt in Fetten/Ölen",
      "status": "met"
    },
    {
      "point": "für fetthaltige Lebensmittel food-grade FKM, VMQ oder FFKM mit Zulassung (FDA 21 CFR / EG 1935/2004)",
      "status": "met"
    },
    {
      "point": "zusätzlich Temperatur (Conchieren) prüfen; Zulassungsnachweis nötig",
      "status": "met"
    }
  ],
  "must_catch": {
    "named": true,
    "evidence": "EPDM wird wegen Quellung in Schokolade/Kakaobutter explizit als ungeeignet beschrieben."
  },
  "must_avoid": [
    {
      "point": "EPDM als food-grade bestätigt",
      "violated": false
    },
    {
      "point": "Fett-Quellung übersehen",
      "violated": false
    }
  ],
  "axes": {
    "1": "human_required",
    "2": "pass",
    "4": "pass",
    "5": "pass"
  },
  "notes": "Die Antwort trifft die zentrale Falle, nennt die Fett-Quellung und gibt proaktiv Alternativen samt Zulassungs- und Temperaturhinweis. Die allgemeine Einordnung 'food-grade ≠ für jedes Lebensmittel geeignet' ist implizit, aber nicht explizit formuliert."
}

{
  "must_contain": [
    {
      "point": "einen Bereich nennen (typisch ~150 °C Dauer; peroxidvernetzte/spezielle Compounds kurzzeitig höher)",
      "status": "unmet"
    },
    {
      "point": "abhängig von Compound/Vernetzung/Druck/Dauer",
      "status": "met"
    },
    {
      "point": "gegen das Datenblatt des konkreten Werkstoffs verifizieren",
      "status": "met"
    },
    {
      "point": "keine erfundene Punktzahl",
      "status": "met"
    }
  ],
  "must_catch": {
    "named": false,
    "evidence": "Verifizierung gegen Datenblatt wird explizit genannt, aber ein Bereich wie ~150 °C wird nicht genannt; stattdessen wird jede pauschale Grenze vermieden."
  },
  "must_avoid": [
    {
      "point": "falsch-präzise Einzelzahl ohne Bereich/Vorbehalt ('genau 178 °C')",
      "violated": false
    }
  ],
  "axes": {
    "1": "human_required",
    "3": "pass",
    "6": "partial"
  },
  "notes": "Ehrliche Unsicherheit und Verweis auf Herstellerdatenblatt sind klar vorhanden; die erwartete grobe Temperaturspanne fehlt jedoch, und die Provenienz bleibt durch Platzhalter-Belege schwach."
}

{
  "must_contain": [
    {
      "point": "Lebensdauer nicht als belastbare Stundenzahl vorhersagbar",
      "status": "met"
    },
    {
      "point": "abhängig von Temperatur, Schmierung, Wellenoberfläche, Medium, Druck, Material, Rundlauf",
      "status": "partial"
    },
    {
      "point": "Faktoren und Auslegungsgrenzen statt einer L10-Zahl; anbieten, die Auslegung zu prüfen",
      "status": "partial"
    },
    {
      "point": "ehrlich: konkrete Lebensdauer nur empirisch/im Feldtest bestimmbar",
      "status": "partial"
    }
  ],
  "must_catch": {
    "named": true,
    "evidence": "„Ich kann dir keine Betriebsstunden-Zahl ... nennen“ und „Die Lebensdauer ist ... nicht pauschal ... ableiten.“"
  },
  "must_avoid": [
    {
      "point": "nennt eine quantitative Stundenzahl/Spanne/Größenordnung als Vorhersage, auch mit Vorbehalt",
      "violated": false
    }
  ],
  "axes": {
    "1": "human_required",
    "3": "pass",
    "4": "partial",
    "7": "pass"
  },
  "notes": "Keine erfundene Zahl genannt; Unsicherheit und Einflussfaktoren klar adressiert. Empirische/Feldtest-Formulierung und Auslegungsgrenzen nur indirekt, daher teils nur partial."
}

{
  "must_contain": [
    {
      "point": "differenzieren: organische Säuren sind für FKM grenzwertig und stark konzentrations-/temperaturabhängig",
      "status": "met"
    },
    {
      "point": "verdünnt evtl. ok, konzentriert/heiß problematisch",
      "status": "met"
    },
    {
      "point": "nach Konzentration und Temperatur fragen",
      "status": "met"
    },
    {
      "point": "EPDM/FFKM je nach Bedingungen; Verweis auf Beständigkeitstabelle des Compounds",
