}

{
  "must_contain": [
    {
      "point": "Konflikt offenlegen: Aceton (Keton) greift NBR/FKM an",
      "status": "met"
    },
    {
      "point": "EPDM gegen Aceton ok, aber 180 °C dauerhaft für Standard-EPDM grenzwertig",
      "status": "met"
    },
