}

{
  "must_contain": [
    {
      "point": "warnen: FKM wird von Aminen angegriffen (auch aminhaltige Korrosionsinhibitoren/Kühlmittel)",
      "status": "met"
    },
    {
      "point": "der Vorprojekt-Erfolg überträgt sich nicht, weil das Medium anders ist",
      "status": "met"
